// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation helpers
  const isValidEmail = useCallback((value: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  }, []);

  const getNameError = useCallback(() => {
    if (currentStep === 1 && name.trim() === '') return 'Name is required';
    return '';
  }, [currentStep, name]);

  const getEmailError = useCallback(() => {
    if (currentStep === 1) {
      if (email.trim() === '') return 'Email is required';
      if (!isValidEmail(email)) return 'Please enter a valid email address';
    }
    return '';
  }, [currentStep, email, isValidEmail]);

  const isStep1Valid = useCallback(() => {
    return name.trim() !== '' && email.trim() !== '' && isValidEmail(email);
  }, [name, email, isValidEmail]);

  const isStep2Valid = useCallback(() => {
    return satisfaction !== '';
  }, [satisfaction]);

  const isStep3Valid = useCallback(() => {
    return features.length > 0;
  }, [features]);

  const canProceedToNext = useCallback(() => {
    if (currentStep === 1) return isStep1Valid();
    if (currentStep === 2) return isStep2Valid();
    if (currentStep === 3) return isStep3Valid();
    return true;
  }, [currentStep, isStep1Valid, isStep2Valid, isStep3Valid]);

  const handleNext = useCallback(() => {
    if (canProceedToNext() && currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, canProceedToNext]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleFeatureToggle = useCallback((feature: string) => {
    setFeatures(prev => {
      if (prev.includes(feature)) {
        return prev.filter(f => f !== feature);
      } else {
        return [...prev, feature];
      }
    });
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim(),
    });
  }, [submit, name, email, satisfaction, features, comments]);

  const satisfactionOptions = useMemo(() => {
    return props.satisfactionLabels.map((label, index) => ({
      value: String(index + 1),
      label: `${index + 1} - ${label}`,
    }));
  }, [props.satisfactionLabels]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Progress Header */}
        <Box>
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Multi-Step Survey</Heading>
            <Progress
              value={currentStep}
              max={5}
              variant="default"
              size="md"
              showLabel={true}
            />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Step {currentStep} of 5
            </Text>
          </Stack>
        </Box>

        {/* Step Content */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Your Information</Heading>
                <Input
                  label="Name"
                  placeholder="Enter your full name"
                  value={name}
                  onChange={setName}
                  required={true}
                  error={getNameError()}
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="you@example.com"
                  value={email}
                  onChange={setEmail}
                  required={true}
                  error={getEmailError()}
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Satisfaction Rating</Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  How satisfied are you with our service?
                </Text>
                <RadioGroup
                  label="Select your rating"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  direction="vertical"
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Feature Interests</Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  Which features are you most interested in? (Select at least one)
                </Text>
                <Stack gap="var(--ggui-spacing-3)">
                  {props.featureOptions.map((feature, idx) => (
                    <Checkbox
                      key={`feature-${idx}`}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={() => handleFeatureToggle(feature)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {currentStep === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Additional Comments</Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  Please share any additional feedback (optional, max 500 characters)
                </Text>
                <TextArea
                  label="Comments"
                  placeholder="Share your thoughts here..."
                  value={comments}
                  onChange={setComments}
                  maxLength={500}
                  showCount={true}
                  rows={6}
                />
              </Stack>
            )}

            {currentStep === 5 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={3}>Review Your Answers</Heading>
                <Card padding="var(--ggui-spacing-4)" shadow="none" border={true}>
                  <Stack gap="var(--ggui-spacing-4)">
                    <Box>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Name
                      </Text>
                      <Text variant="body">{name}</Text>
                    </Box>
                    <Divider />
                    <Box>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Email
                      </Text>
                      <Text variant="body">{email}</Text>
                    </Box>
                    <Divider />
                    <Box>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Satisfaction Rating
                      </Text>
                       <Text variant="body">
                         {satisfaction ? `${satisfaction} - ${props.satisfactionLabels[Math.min(parseInt(satisfaction, 10) - 1, props.satisfactionLabels.length - 1)]}` : 'Not selected'}
                       </Text>
                    </Box>
                    <Divider />
                    <Box>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Selected Features
                      </Text>
                      <Stack gap="var(--ggui-spacing-2)" direction="horizontal" wrap={true}>
                        {features.length > 0 ? (
                          features.map(feature => (
                            <Badge key={feature} variant="primary" size="sm">
                              {feature}
                            </Badge>
                          ))
                        ) : (
                          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                            No features selected
                          </Text>
                        )}
                      </Stack>
                    </Box>
                    <Divider />
                    <Box>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Comments
                      </Text>
                      <Text variant="body">
                        {comments || '(No comments provided)'}
                      </Text>
                    </Box>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Stack>
        </Card>

        {/* Navigation Buttons */}
        <Stack direction="horizontal" justify="between" gap="var(--ggui-spacing-4)">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={!canProceedToNext()}
            >
              {currentStep === 4 ? 'Review' : 'Next'}
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit Survey
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

