import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Task card component for individual task display
interface TaskCardProps {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  columns: Array<{ id?: string; name?: string }>;
  onMove: (taskId: string, newColumn: string) => void;
  onEdit: (taskId: string, newTitle: string) => void;
}

function TaskCard(props: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(props.task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);
  const titleRef = useRef<HTMLDivElement>(null);
  const clickTimeRef = useRef<number>(0);

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'var(--ggui-color-error-500)';
      case 'medium':
        return 'var(--ggui-color-warning-500)';
      case 'low':
      default:
        return 'var(--ggui-color-success-500)';
    }
  };

  const getPriorityLabel = (priority?: string) => {
    return priority ? priority.charAt(0).toUpperCase() + priority.slice(1) : 'Low';
  };

  const handleSaveEdit = () => {
    if (editTitle.trim() && props.task.id) {
      props.onEdit(props.task.id, editTitle.trim());
      setIsEditing(false);
    }
  };

  const handleTitleDoubleClick = () => {
    setEditTitle(props.task.title || '');
    setIsEditing(true);
  };

  const handleMove = (columnId?: string) => {
    if (columnId && props.task.id) {
      props.onMove(props.task.id, columnId);
      setShowMoveMenu(false);
    }
  };

  return (
    <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-2)" direction="horizontal">
            <Input
              label="Task title"
              value={editTitle}
              onChange={setEditTitle}
              placeholder="Enter task title"
              size="sm"
            />
            <Button size="sm" variant="primary" onClick={handleSaveEdit}>Save</Button>
            <Button size="sm" variant="ghost" onClick={() => setIsEditing(false)}>Cancel</Button>
          </Stack>
         ) : (
           <Stack gap="var(--ggui-spacing-3)">
             <Row justify="between" align="center">
               <Text
                 ref={titleRef}
                 variant="body"
                 weight="medium"
                 onDoubleClick={handleTitleDoubleClick}
                 style={{ flex: 1, cursor: 'text' }}
               >
                 {props.task.title || 'Untitled'}
               </Text>
               <Button
                 size="xs"
                 variant="ghost"
                 onClick={() => {
                   setEditTitle(props.task.title || '');
                   setIsEditing(true);
                 }}
               >
                 <Icon name="edit-2" size={14} />
               </Button>
             </Row>
             <Row gap="var(--ggui-spacing-2)" align="center">
               <Badge
                 variant={props.task.priority === 'high' ? 'error' : props.task.priority === 'medium' ? 'warning' : 'success'}
                 size="sm"
               >
                 {getPriorityLabel(props.task.priority)}
               </Badge>
               {props.task.assignee && (
                 <Avatar name={props.task.assignee} size="xs" shape="circle" />
               )}
               {props.task.dueDate && (
                 <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                   {new Date(props.task.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                 </Text>
               )}
             </Row>
             <Dropdown
               trigger={<Button size="xs" variant="outline">Move</Button>}
               options={props.columns
                 .filter(col => col.id !== props.task.column)
                 .map(col => ({ value: col.id || '', label: col.name || 'Column' })) || []}
               value=""
               onChange={handleMove}
               placement="bottom-start"
             />
           </Stack>
    </Card>
  );
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State for tasks and column management
  const [tasks, setTasks] = useState(props.tasks || []);
  const [newTaskColumn, setNewTaskColumn] = useState(props.columns?.[0]?.id || 'todo');
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');
  const [showAddForm, setShowAddForm] = useState<string | null>(null);

  // Handle real-time stream updates from other users
  useEffect(() => {
    if (taskChanged.latest?.task) {
      const updatedTask = taskChanged.latest.task;
      const action = taskChanged.latest.action;

      if (action === 'delete' && updatedTask.id) {
        setTasks(prev => prev.filter(t => t.id !== updatedTask.id));
      } else if (action === 'create') {
        setTasks(prev => [
          ...prev,
          { ...updatedTask, id: updatedTask.id || `task-${Date.now()}` }
        ]);
      } else if (action === 'move' || action === 'edit') {
        setTasks(prev => prev.map(t => t.id === updatedTask.id ? { ...t, ...updatedTask } : t));
      }
    }
  }, [taskChanged.latest]);

  // Handle moving a task to another column
  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn } : t));
  }, [taskUpdate]);

  // Handle editing a task title
  // Handle editing a task title
  const handleEditTask = useCallback((taskId: string, newTitle: string) => {
    taskUpdate({ action: 'edit', taskId, data: { column: '', title: newTitle } });
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, title: newTitle } : t));
  }, [taskUpdate]);

  // Handle adding a new task
  const handleAddTask = useCallback((columnId: string) => {
    if (newTaskTitle.trim()) {
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority as 'low' | 'medium' | 'high',
        assignee: '',
        dueDate: '',
        column: columnId
      };
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
      setTasks(prev => [...prev, newTask]);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setShowAddForm(null);
    }
  }, [newTaskTitle, newTaskPriority, taskUpdate]);

  // Calculate task counts per column
  const taskCountByColumn = useMemo(() => {
    const counts: { [key: string]: number } = {};
    props.columns?.forEach(col => {
      counts[col.id || ''] = tasks.filter(t => t.column === col.id).length;
    });
    return counts;
  }, [tasks, props.columns]);

  // Calculate summary stats
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.column === props.columns?.[props.columns.length - 1]?.id).length;

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary bar at the top */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
              <Stack align="start">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Total Tasks</Text>
                <Heading level={3}>{totalTasks}</Heading>
              </Stack>
              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" />
              <Stack align="start">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Completed</Text>
                <Heading level={3}>{completedTasks}</Heading>
              </Stack>
            </Stack>
            <Badge variant="primary" size="lg">{Math.round((completedTasks / Math.max(totalTasks, 1)) * 100)}% Done</Badge>
          </Row>
        </Card>

        {/* Kanban board with columns */}
        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {props.columns?.map(column => {
            const columnTasks = tasks.filter(t => t.column === column.id);
            return (
              <Box
                key={column.id}
                padding="var(--ggui-spacing-4)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-lg)"
                style={{ minWidth: '320px', maxWidth: '360px', minHeight: '600px' }}
              >
                <Stack gap="var(--ggui-spacing-4)">
                  {/* Column header */}
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="secondary" size="sm">{taskCountByColumn[column.id || ''] || 0}</Badge>
                  </Row>

                  {/* Column divider */}
                  <Divider orientation="horizontal" margin={0} color="var(--ggui-color-outline)" />

                  {/* Task list */}
                  <Stack gap="var(--ggui-spacing-3)" style={{ flex: 1, overflowY: 'auto' }}>
                    {columnTasks.length > 0 ? (
                      columnTasks.map(task => (
                        <TaskCard
                          key={task.id}
                          task={task}
                          columns={props.columns || []}
                          onMove={handleMoveTask}
                          onEdit={handleEditTask}
                        />
                      ))
                    ) : (
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant)"
                        align="center"
                        style={{ paddingTop: 'var(--ggui-spacing-4)' }}
                      >
                        No tasks
                      </Text>
                    )}
                  </Stack>

                  {/* Add task form or button */}
                  {showAddForm === column.id ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                          size="sm"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={setNewTaskPriority}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />
                        <Row gap="var(--ggui-spacing-2)" justify="end">
                          <Button size="sm" variant="ghost" onClick={() => setShowAddForm(null)}>Cancel</Button>
                          <Button size="sm" variant="primary" onClick={() => handleAddTask(column.id || '')}>Add</Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      fullWidth
                      variant="outline"
                      size="sm"
                      onClick={() => setShowAddForm(column.id || '')}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

