}





// Helper: Map category to color token
const categoryColorMap: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-100)',
  'noble gas': 'var(--ggui-color-success-100)',
  'halogen': 'var(--ggui-color-warning-100)',
  'alkali metal': 'var(--ggui-color-error-100)',
  'alkaline earth metal': 'var(--ggui-color-info-100)',
  'transition metal': 'var(--ggui-color-primary-200)',
  'lanthanide': 'var(--ggui-color-primary-300)',
  'actinide': 'var(--ggui-color-warning-200)',
  'metalloid': 'var(--ggui-color-primary-50)',
  'other nonmetal': 'var(--ggui-color-primary-100)',
};

const getCategoryColor = (category?: string): string => {
  if (!category) return 'var(--ggui-color-surfaceVariant)';
  const lower = category.toLowerCase();
  return categoryColorMap[lower] || 'var(--ggui-color-surfaceVariant)';
};

const getCategoryBadgeVariant = (category?: string): 'default' | 'primary' | 'success' | 'warning' | 'error' | 'info' => {
  if (!category) return 'default';
  const lower = category.toLowerCase();
  if (['noble gas'].includes(lower)) return 'success';
  if (['halogen'].includes(lower)) return 'warning';
  if (['alkali metal', 'alkaline earth metal'].includes(lower)) return 'error';
  if (['lanthanide', 'actinide'].includes(lower)) return 'info';
  return 'primary';
};

export default function Component(props: Props) {
  // State: search filter, selected element
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Compute: filtered elements by search query (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const lowerQuery = searchQuery.toLowerCase();
    return props.elements.filter((el) =>
      (el.name?.toLowerCase().includes(lowerQuery) || false) ||
      (el.symbol?.toLowerCase().includes(lowerQuery) || false)
    );
  }, [searchQuery, props.elements]);

  // Compute: unique categories for legend
  const uniqueCategories = useMemo(() => {
    const cats = new Set(props.elements.map(el => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [props.elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Click on any element to view details. Use the search below to filter by name or symbol.
          </Text>
        </Stack>

        {/* Search Input */}
        <Box>
          <Input
            label="Search by element name or symbol"
            placeholder="e.g., Hydrogen, H, Gold, Au"
            value={searchQuery}
            onChange={setSearchQuery}
            type="search"
          />
        </Box>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Legend (Categories)</Text>
            <Row gap="var(--ggui-spacing-2)" wrap>
              {uniqueCategories.map((cat) => (
                <Row key={cat} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    padding="var(--ggui-spacing-2)"
                    background={getCategoryColor(cat)}
                    borderRadius="var(--ggui-shape-radius-sm)"
                    style={{ width: '24px', height: '24px' }}
                  />
                  <Text variant="bodySmall">{cat}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1)',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-2)',
          }}
        >
          {filteredElements.map((element) => (
            <Card
              key={`${element.atomicNumber}`}
              as={Clickable}
              onClick={() => setSelectedElement(element)}
              padding="var(--ggui-spacing-2)"
              shadow={selectedElement?.atomicNumber === element.atomicNumber ? 'md' : 'sm'}
              style={{
                gridRow: element.row,
                gridColumn: element.col,
                background: getCategoryColor(element.category),
                cursor: 'pointer',
                transition: 'all 200ms ease-in-out',
                border: selectedElement?.atomicNumber === element.atomicNumber
                  ? '2px solid var(--ggui-color-primary-600)'
                  : 'none',
              }}
              hoverStyle={{
                opacity: 0.85,
                transform: 'scale(1.05)',
              }}
            >
              <Stack gap="var(--ggui-spacing-1)" align="center" justify="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant)"
                  align="left"
                  style={{ alignSelf: 'flex-start', fontSize: 'var(--ggui-font-size-xs)' }}
                >
                  {element.atomicNumber}
                </Text>
                <Text
                  variant="label"
                  size="lg"
                  weight="bold"
                  color="var(--ggui-color-onSurface)"
                  align="center"
                >
                  {element.symbol}
                </Text>
              </Stack>
            </Card>
          ))}
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-4)" shadow="md" border>
            <Stack gap="var(--ggui-spacing-3)">
              <Row gap="var(--ggui-spacing-3)" align="start">
                <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
                  <Heading level={2}>{selectedElement.name}</Heading>
                  <Row gap="var(--ggui-spacing-2)" align="center">
                    <Badge variant={getCategoryBadgeVariant(selectedElement.category)}>
                      {selectedElement.category || 'Unknown'}
                    </Badge>
                  </Row>
                </Stack>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  Close
                </Button>
              </Row>

              <Divider />

              <Stack gap="var(--ggui-spacing-2)">
                <Row gap="var(--ggui-spacing-4)" justify="between">
                  <Box>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                      Symbol
                    </Text>
                    <Text variant="bodyLarge" weight="medium">
                      {selectedElement.symbol}
                    </Text>
                  </Box>
                  <Box>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                      Atomic Number
                    </Text>
                    <Text variant="bodyLarge" weight="medium">
                      {selectedElement.atomicNumber}
                    </Text>
                  </Box>
                  <Box>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                      Atomic Weight
                    </Text>
                    <Text variant="bodyLarge" weight="medium">
                      {selectedElement.atomicWeight?.toFixed(3) || 'N/A'}
                    </Text>
                  </Box>
                  <Box>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                      Row
                    </Text>
                    <Text variant="bodyLarge" weight="medium">
                      {selectedElement.row || 'N/A'}
                    </Text>
                  </Box>
                  <Box>
                    <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                      Column
                    </Text>
                    <Text variant="bodyLarge" weight="medium">
                      {selectedElement.col || 'N/A'}
                    </Text>
                  </Box>
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Empty State */}
        {filteredElements.length === 0 && (
          <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
            <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
              <Icon name="search" size={32} color="var(--ggui-color-onSurfaceVariant)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No elements found matching "{searchQuery}"
              </Text>
              <Button
                variant="outline"
                size="sm"
                onClick={() => setSearchQuery('')}
              >
                Clear Search
              </Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

