}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State management
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Derived values
  const isOutOfStock = !props.product.stock || props.product.stock === 0;
  const isLowStock = props.product.stock && props.product.stock > 0 && props.product.stock <= 5;
  const maxQuantity = props.product.stock || 1;
  const formattedPrice = props.product.price !== undefined && props.product.currency ? `${props.product.currency}${props.product.price.toFixed(2)}` : 'N/A';
  const rating = props.product.rating || 0;
  const filledStars = Math.round(rating);

  // Handlers
  const handleQuantityChange = useCallback((newQuantity: number) => {
    setQuantity(Math.max(1, Math.min(newQuantity, maxQuantity)));
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  // Specifications render function
  const renderSpecifications = useMemo(() => {
    if (!Array.isArray(props.product.specifications) || props.product.specifications.length === 0) {
      return <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available</Text>;
    }
    const specs = props.product.specifications as Array<{ key?: string; value?: string | number }>;
    return (
      <Stack gap="var(--ggui-spacing-3)" direction="vertical">
        {specs.map((spec, idx) => (
          <Row key={idx} justify="between" align="center" gap="var(--ggui-spacing-4)">
