            <Text variant="body" color="var(--ggui-color-onSurface)">{spec.value || 'N/A'}</Text>
          </Row>
        ))}
      </Stack>
    );
  }, [props.product.specifications]);

  // Reviews render function
  const renderReviews = useMemo(() => {
    if (!Array.isArray(props.product.reviews) || props.product.reviews.length === 0) {
      return <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet</Text>;
    }
    const reviews = props.product.reviews as Array<{ author?: string; rating?: number; text?: string; date?: string | Date }>;
    return (
      <Stack gap="var(--ggui-spacing-4)" direction="vertical">
        {reviews.map((review, idx) => (
          <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm" border>
            <Stack gap="var(--ggui-spacing-2)" direction="vertical">
              <Row justify="between" align="center" gap="var(--ggui-spacing-2)">
                <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">{review.author || 'Anonymous'}</Text>
                <Badge variant="primary" size="sm">{review.rating || 0}/5</Badge>
              </Row>
              <Text variant="body" color="var(--ggui-color-onSurface)">{review.text || ''}</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{typeof review.date === 'string' ? review.date : review.date ? new Date(review.date).toLocaleDateString() : 'N/A'}</Text>
            </Stack>
          </Card>
        ))}
      </Stack>
    );
  }, [props.product.reviews]);

  // Star rating component
  const renderStars = useMemo(() => {
    return (
      <Row gap="var(--ggui-spacing-1)" align="center">
        {[1, 2, 3, 4, 5].map((star) => (
          <Icon
            key={star}
            name={star <= filledStars ? 'star' : 'star-off'}
            size={18}
            color={star <= filledStars ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
          />
        ))}
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ marginLeft: 'var(--ggui-spacing-2)' }}>
          {rating.toFixed(1)} ({props.product.reviewCount || 0} reviews)
        </Text>
      </Row>
    );
  }, [rating, filledStars, props.product.reviewCount]);

  // Tab items for Tabs component
  const tabItems = useMemo(() => [
    {
      key: 'description',
      label: 'Description',
      content: <Text color="var(--ggui-color-onSurface)">{props.product.description || 'No description available'}</Text>,
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: renderSpecifications,
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: renderReviews,
    },
  ], [props.product.description, renderSpecifications, renderReviews]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" direction="vertical">
        {/* Top Section: Image and Product Details */}
        <Row gap="var(--ggui-spacing-6)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            padding="var(--ggui-spacing-6)"
            background="var(--ggui-color-primary-100)"
            borderRadius="var(--ggui-shape-radius-lg)"
            style={{ flex: '0 0 300px', minHeight: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Text variant="label" align="center" color="var(--ggui-color-primary-700)">{props.product.name || 'Product Image'}</Text>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" direction="vertical" style={{ flex: 1, minWidth: '280px' }}>
            {/* Title */}
            <Heading level={2} color="var(--ggui-color-onSurface)">{props.product.name || 'Product Name'}</Heading>

            {/* Price */}
            <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-primary-600)">{formattedPrice}</Text>

            {/* Rating Stars */}
            {renderStars}

            {/* Stock Status Badge */}
            <Box>
              {isOutOfStock ? (
                <Badge variant="error" size="md">Out of Stock</Badge>
              ) : isLowStock ? (
                <Badge variant="warning" size="md">Low Stock ({props.product.stock} left)</Badge>
              ) : (
                <Badge variant="success" size="md">In Stock</Badge>
              )}
            </Box>
          </Stack>
        </Row>

        {/* Middle Section: Tab Navigation */}
        <Tabs
          variant="line"
          items={tabItems}
          activeKey={activeTab}
          onChange={setActiveTab}
          size="md"
        />

        {/* Bottom Section: Quantity Selector and Add to Cart */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)" direction="vertical">
            {/* Quantity Selector */}
            <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Quantity:</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleQuantityChange(quantity - 1)}
                  disabled={quantity <= 1}
                >
                  −
                </Button>
                <Text variant="body" style={{ minWidth: '40px', textAlign: 'center', fontWeight: 'var(--ggui-font-weight-medium)' }} color="var(--ggui-color-onSurface)">{quantity}</Text>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleQuantityChange(quantity + 1)}
                  disabled={quantity >= maxQuantity}
                >
                  +
                </Button>
              </Row>
            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              fullWidth
              onClick={handleAddToCart}
              disabled={isOutOfStock}
