type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [messages, setMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  // Handle message submission
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue.trim(), timestamp });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Handle Enter key to send message
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Check if typing indicator should show
  const isTyping = typing.latest?.active === true && typing.latest?.sender && typing.latest.sender !== props.currentUser;
  const typingSender = typing.latest?.sender;

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    for (const msg of messages) {
      if (groups.length > 0 && groups[groups.length - 1].sender === msg.sender) {
        groups[groups.length - 1].messages.push(msg);
      } else {
        groups.push({ sender: msg.sender, messages: [msg] });
      }
    }
    return groups;
  }, [messages]);

  return (
    <Card shadow="md" radius="lg" border padding="var(--ggui-spacing-4)" style={{ display: 'flex', flexDirection: 'column', height: '100%', maxHeight: '80vh' }}>
