      <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-4)" style={{ paddingBottom: 'var(--ggui-spacing-4)', borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
        <Heading level={3}>{props.title}</Heading>
        <Badge variant="primary" size="md">
          {props.participantCount} {props.participantCount === 1 ? 'participant' : 'participants'}
        </Badge>
      </Stack>

      {/* Message List */}
      <Stack gap="var(--ggui-spacing-3)" style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4) 0', minHeight: '200px' }}>
        {groupedMessages.length === 0 ? (
          <Text color="var(--ggui-color-onSurfaceVariant)" align="center" style={{ margin: 'auto' }}>
            No messages yet. Start the conversation!
          </Text>
        ) : (
          groupedMessages.map((group, groupIdx) => {
            const isCurrentUser = group.sender === props.currentUser;
            return (
              <Stack key={groupIdx} gap="var(--ggui-spacing-2)" align={isCurrentUser ? 'end' : 'start'} style={{ maxWidth: '80%', marginLeft: isCurrentUser ? 'auto' : 0 }}>
                {group.sender && !isCurrentUser && (
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ fontSize: 'var(--ggui-font-size-xs)' }}>
                    {group.sender}
                  </Text>
                )}
                <Stack gap="var(--ggui-spacing-1)" align={isCurrentUser ? 'end' : 'start'}>
                  {group.messages.map((msg, msgIdx) => (
                    <Box
                      key={msgIdx}
                      padding="var(--ggui-spacing-3)"
                      borderRadius="var(--ggui-shape-radius-lg)"
                      background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                    >
                      <Text
                        variant="body"
                        color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'}
                      >
                        {msg.text}
                      </Text>
                      {msg.timestamp && (
                        <Text
                          variant="caption"
                          color={isCurrentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                          style={{ marginTop: 'var(--ggui-spacing-1)' }}
                        >
                          {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </Text>
                      )}
                    </Box>
                  ))}
                </Stack>
              </Stack>
            );
          })
        )}
        {isTyping && (
          <Stack gap="var(--ggui-spacing-1)" align="start" style={{ maxWidth: '80%' }}>
            <Box padding="var(--ggui-spacing-3)" borderRadius="var(--ggui-shape-radius-lg)" background="var(--ggui-color-surfaceVariant)">
              <Text variant="body" color="var(--ggui-color-onSurface)">
                {typingSender} is typing
                <span style={{ animation: 'ggui-pulse 1.5s ease-in-out infinite' }}>...</span>
              </Text>
            </Box>
          </Stack>
        )}
        <div ref={messagesEndRef} />
      </Stack>

      {/* Input Area */}
      <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="end" style={{ paddingTop: 'var(--ggui-spacing-4)', borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
        <TextArea
          label="Message"
          value={inputValue}
          onChange={setInputValue}
          placeholder="Type your message here..."
          rows={2}
          style={{ flex: 1 }}
        />
        <Button
          variant="primary"
          disabled={!inputValue.trim()}
          onClick={handleSendMessage}
          style={{ flexShrink: 0 }}
          size="md"
        >
          Send Message
        </Button>
      </Stack>
    </Card>
  );
}

