  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: track displayed stocks (merged with price updates)
  const [displayedStocks, setDisplayedStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const animationTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Effect: Merge incoming price updates into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const updated = { ...priceUpdate.latest };
      setDisplayedStocks(prev => {
        return prev.map(stock => {
          if (stock.symbol === updated.symbol) {
            return { ...stock, ...updated };
          }
          return stock;
        });
      });
      setLastUpdated(new Date());

      // Highlight the updated stock briefly
      if (updated.symbol) {
        setHighlightedSymbols(prev => new Set(prev).add(updated.symbol));

        // Clear highlight after animation duration
        if (animationTimeoutRef.current) {
          clearTimeout(animationTimeoutRef.current);
        }
        animationTimeoutRef.current = setTimeout(() => {
          setHighlightedSymbols(prev => {
            const next = new Set(prev);
            next.delete(updated.symbol!);
            return next;
          });
        }, 700);
      }
    }
  }, [priceUpdate.latest]);

  // Cleanup timeout on unmount
  useEffect(() => {
    return () => {
      if (animationTimeoutRef.current) {
        clearTimeout(animationTimeoutRef.current);
      }
    };
  }, []);
  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <style>{`
        @keyframes ggui-flash {
          0% { background-color: var(--ggui-flash-color, var(--ggui-color-primary-100)); }
