              Market Watch
            </Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {lastUpdated ? lastUpdated.toLocaleTimeString() : 'Never'}
            </Text>
          </Stack>
          {marketStatus.latest && (
            <Badge
              variant={marketStatus.latest.status === 'open' ? 'success' : marketStatus.latest.status === 'pre-market' ? 'warning' : 'default'}
              size="md"
            >
              {(marketStatus.latest.status || 'unknown').toUpperCase()}
            </Badge>
          )}
        </Row>
      </Box>

      {/* Grid of Stock Cards - Responsive: 3 cols desktop, 1 col mobile */}
      <Box
        role="region"
        aria-label="Stock listings"
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
          gap: 'var(--ggui-spacing-4)',
        } as React.CSSProperties}
      >
        {displayedStocks.map((stock, idx) => (
          <StockCard
            key={stock.symbol || idx}
            stock={stock}
            isHighlighted={stock.symbol ? highlightedSymbols.has(stock.symbol) : false}
          />
        ))}
