            onChange={(value) => handleInputChange('theme', value ? 'dark' : 'light')}
            size="md"
          />
        </Stack>
      );
    }

    if (currentStep === 3) {
      return (
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={3}>Review Your Information</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Please review all your settings before completing the setup.
          </Text>

          <Card shadow="md" padding="var(--ggui-spacing-4)" border>
            <Stack gap="var(--ggui-spacing-3)">
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Avatar</Text>
                <Text variant="body" style={{ fontSize: '32px', marginTop: '8px' }}>{formData.avatar}</Text>
              </Box>

              <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                <Text variant="body">{formData.name}</Text>
              </Box>

              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                <Text variant="body">{formData.email}</Text>
              </Box>

              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                <Text variant="body">{formData.role}</Text>
              </Box>

              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email Notifications</Text>
                <Badge variant={formData.emailNotifications ? 'success' : 'default'}>
                  {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                </Badge>
              </Box>

              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                <Badge variant="primary">
                  {formData.theme.charAt(0).toUpperCase() + formData.theme.slice(1)}
                </Badge>
              </Box>
            </Stack>
          </Card>
        </Stack>
      );
    }
  };

  const isStep1Valid = formData.name.trim() && formData.email.trim() && validateEmail(formData.email);
  const isStep2Valid = formData.role !== '';

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <StepIndicator currentStep={currentStep} totalSteps={3} />

      <Card shadow="md" padding="var(--ggui-spacing-6)" border>
        {renderStepContent()}
      </Card>

      <Stack direction="horizontal" gap="var(--ggui-spacing-3)" justify="start" align="center" style={{ marginTop: 'var(--ggui-spacing-6)' }}>
        {currentStep > 1 && (
          <Button variant="outline" onClick={handleBack}>
            Go Back
          </Button>
        )}
        <Spacer size="flex" />
        {currentStep < 3 && (
          <Button variant="primary" onClick={handleNext} disabled={currentStep === 1 && !isStep1Valid || currentStep === 2 && !isStep2Valid}>
            Next
          </Button>
        )}
        {currentStep === 3 && (
          <Button variant="primary" onClick={handleComplete}>
            Complete Setup
          </Button>
        )}
      </Stack>
    </Container>
  );
}
